// Filtrar leads que cumplen la cadencia de tiempo
// FIX M4: tambien excluir emails que hayan hecho opt-out (campo unsubscribed)
const now = new Date();

const eligible = $input.all().filter(item => {
  const lead = item.json;

  // FIX M4: verificar campo unsubscribed si existe
  if (lead.unsubscribed) return false;
  if (lead.email_bounced) return false;

  const lastTouch = lead.last_touch_at ? new Date(lead.last_touch_at) : new Date(lead.created_at);
  const daysSince = (now - lastTouch) / (1000 * 60 * 60 * 24);
  const touchCount = lead.touch_count || 0;

  // Cadencia de follow-up
  if (touchCount === 0 && daysSince >= 1) return true;   // D1: 1 dia despues de crear
  if (touchCount === 1 && daysSince >= 2) return true;   // D3: 2 dias despues del touch 1
  if (touchCount === 2 && daysSince >= 4) return true;   // D7: 4 dias despues del touch 2
  if (touchCount === 3 && daysSince >= 7) return true;   // D14: 7 dias despues del touch 3

  return false;
});

if (eligible.length === 0) {
  // Si no hay leads elegibles, terminar sin error
  return [{ json: { _empty: true, count: 0, message: 'No leads need follow-up today' } }];
}

console.log(`[follow-up] ${eligible.length} leads elegibles para follow-up`);
return eligible;

